## Problem
LettaChatClient.reloadFromServer() (line 197-209) replaces messages without merge:

```kotlin
private suspend fun reloadFromServer() {
    try {
        val appMessages = messageRepository.fetchMessages(agentId, activeConversationId)
        val chatMessages = appMessages.map { it.toChatMessage() }
        if (chatMessages.isNotEmpty()) {
            _messages.update { chatMessages }  // FULL REPLACE - can cause flash
            seenMessageIds.clear()
            chatMessages.forEach { seenMessageIds.add(it.id) }
        }
    } catch (e: Exception) {
        logWarning("Silent reload failed", e)
    }
}
```

ChatViewModel had the same bug and was fixed with:
1. 500ms delay before reload
2. Merge logic instead of replace

## Solution
Apply same fix to LettaChatClient:

```kotlin
private suspend fun reloadFromServer() {
    kotlinx.coroutines.delay(500)  // Let server persist
    try {
        val appMessages = messageRepository.fetchMessages(agentId, activeConversationId)
        val serverMessages = appMessages.map { it.toChatMessage() }
        if (serverMessages.isNotEmpty()) {
            _messages.update { existing ->
                // Merge: if server has >= messages, use server; else keep existing + new
                if (serverMessages.size >= existing.size) {
                    serverMessages
                } else {
                    val existingIds = existing.map { it.id }.toSet()
                    existing + serverMessages.filter { it.id !in existingIds }
                }
            }
            seenMessageIds.clear()
            _messages.value.forEach { seenMessageIds.add(it.id) }
        }
    } catch (e: Exception) {
        logWarning("Silent reload failed", e)
    }
}
```

## Acceptance Criteria
- [ ] LettaChatClient.reloadFromServer() has 500ms delay
- [ ] Uses merge logic, not full replace
- [ ] No message flash when using LettaChatClient

## Problem
After stream completes, `reloadMessagesFromServer()` fires asynchronously:

```kotlin
// ChatViewModel.kt line 543
StreamState.Complete -> {
    pendingToolsMap.clear()
    val newMessages = state.messages.toUiMessages()
    _uiState.value = _uiState.value.copy(
        messages = (existingMessages + newMessages).toImmutableList(),
        isStreaming = false,
        // ...
    )
    reloadMessagesFromServer()  // FIRE AND FORGET - races with next send
}
```

```kotlin
// line 657
private fun reloadMessagesFromServer() {
    viewModelScope.launch {  // NEW COROUTINE - can race
        // ...
        _uiState.value = _uiState.value.copy(messages = messages.toImmutableList())
    }
}
```

**Race condition**: If user sends another message before reload completes, you have overlapping coroutines updating `_uiState.messages`, causing messages to disappear or duplicate.

## Solution
Two options:
1. **Option A**: Make reload synchronous in the stream collection (await it)
2. **Option B**: Use mutex to serialize state updates

Option A is simpler and ensures consistency.

## Implementation (Option A: Synchronous Reload)

### Step 1: Change StreamState.Complete handling
**File: `app/src/main/java/com/letta/mobile/ui/screens/chat/ChatViewModel.kt`**

```kotlin
fun sendMessage(text: String) {
    viewModelScope.launch {
        // ... setup code ...

        try {
            stream.collect { state ->
                when (state) {
                    is StreamState.Sending -> { /* ... */ }
                    is StreamState.Streaming -> { /* ... */ }
                    is StreamState.ToolExecution -> { /* ... */ }
                    is StreamState.Complete -> {
                        pendingToolsMap.clear()
                        val newMessages = state.messages.toUiMessages()
                        _uiState.value = _uiState.value.copy(
                            messages = (existingMessages + newMessages).toImmutableList(),
                            isStreaming = false,
                            isAgentTyping = false,
                            pendingTools = persistentListOf(),
                        )

                        // SYNCHRONOUS RELOAD - await before allowing next send
                        reloadMessagesFromServerSync()

                        if (projectContext != null) {
                            loadProjectAgents()
                            loadProjectBrief()
                        }
                    }
                    is StreamState.Error -> { /* ... */ }
                }
            }
        } catch (e: Exception) {
            // ...
        }
    }
}
```

### Step 2: Create synchronous reload function
```kotlin
private suspend fun reloadMessagesFromServerSync() {
    try {
        val requestedConversationId = activeConversationId ?: return

        // Small delay to let server persist
        delay(300)

        val appMessages = messageRepository.fetchMessages(
            agentId = agentId,
            conversationId = requestedConversationId,
            targetMessageId = scrollToMessageId?.takeIf { requestedConversationId != null },
        )

        // Check if conversation changed while we were fetching
        if (requestedConversationId != activeConversationId) {
            return
        }

        val serverMessages = appMessages.toUiMessages()
        if (serverMessages.isNotEmpty()) {
            // Use authoritative server state
            _uiState.value = _uiState.value.copy(
                messages = serverMessages.toImmutableList()
            )
        }
    } catch (e: Exception) {
        android.util.Log.w("ChatViewModel", "Sync reload failed", e)
        // Don't clear messages on error - keep what we have
    }
}
```

### Step 3: Remove old async reload (or keep for explicit refresh)
You can either:
- **Delete** `reloadMessagesFromServer()` entirely
- **Rename** it to `refreshMessages()` and only call it from pull-to-refresh UI

```kotlin
// Keep for pull-to-refresh, but don't call after send
fun refreshMessages() {
    viewModelScope.launch {
        reloadMessagesFromServerSync()
    }
}
```

### Step 4: Add loading state during sync reload (optional but nice)
```kotlin
private suspend fun reloadMessagesFromServerSync() {
    try {
        val requestedConversationId = activeConversationId ?: return

        // Don't show loading spinner - messages are already visible
        // Just silently sync in background
        delay(300)

        val appMessages = messageRepository.fetchMessages(...)

        if (requestedConversationId != activeConversationId) return

        val serverMessages = appMessages.toUiMessages()
        if (serverMessages.size >= _uiState.value.messages.size) {
            // Only update if server has at least as many messages
            // This prevents flash when server hasn't persisted yet
            _uiState.value = _uiState.value.copy(
                messages = serverMessages.toImmutableList()
            )
        }
    } catch (e: Exception) {
        android.util.Log.w("ChatViewModel", "Sync reload failed", e)
    }
}
```

## Alternative: Option B (Mutex-based serialization)

If you prefer to keep async reloads but prevent races:

```kotlin
@HiltViewModel
class ChatViewModel @Inject constructor(...) : ViewModel() {
    private val messageUpdateMutex = Mutex()

    private suspend fun updateMessagesState(update: (ImmutableList<UiMessage>) -> ImmutableList<UiMessage>) {
        messageUpdateMutex.withLock {
            _uiState.value = _uiState.value.copy(
                messages = update(_uiState.value.messages)
            )
        }
    }

    private fun reloadMessagesFromServer() {
        viewModelScope.launch {
            delay(500)
            try {
                val appMessages = messageRepository.fetchMessages(...)
                val serverMessages = appMessages.toUiMessages()
                if (serverMessages.isNotEmpty()) {
                    updateMessagesState { serverMessages.toImmutableList() }
                }
            } catch (e: Exception) {
                Log.w("ChatViewModel", "Reload failed", e)
            }
        }
    }

    // In sendMessage(), also use updateMessagesState:
    is StreamState.Streaming -> {
        updateMessagesState { existing ->
            (existing + state.messages.toUiMessages()).toImmutableList()
        }
    }
}
```

## Testing

### Test: No race condition between send and reload
```kotlin
@Test
fun `messages persist after rapid send and reload`() = runTest {
    val viewModel = createChatViewModel()

    // Send first message
    viewModel.sendMessage("Hello")
    advanceUntilIdle()

    // Immediately send second message (before reload completes)
    viewModel.sendMessage("World")
    advanceUntilIdle()

    // Both messages should be present
    val messages = viewModel.uiState.value.messages
    assertTrue(messages.any { it.content == "Hello" })
    assertTrue(messages.any { it.content == "World" })
}
```

## Acceptance Criteria
- [ ] reloadMessagesFromServer is synchronous (awaited) after stream complete
- [ ] No fire-and-forget coroutines updating message state
- [ ] Rapid message sends don't cause message loss
- [ ] Server sync happens but doesn't race with UI updates
- [ ] Optional: Mutex protection for all message state updates
- [ ] Test verifies no race condition

## Problem
`activeConversationId` is tracked in THREE separate places:

1. **ChatViewModel.activeConversationId** (line 172)
   ```kotlin
   private var activeConversationId: String? = savedStateHandle.get<String>("conversationId")
   ```

2. **LettaChatClient.activeConversationId** (line 48)
   ```kotlin
   private var activeConversationId: String? = initialConversationId
   ```

3. **sendProjectMessageViaGateway can update it** (line 582)
   ```kotlin
   response.conversationId
       ?.takeIf { it.isNotBlank() && it != activeConversationId }
       ?.let { activeConversationId = it }
   ```

These can desync, causing messages to be sent to one conversation but loaded from another.

## Solution
Move conversation management to a dedicated `ConversationManager` that is the single source of truth. All components observe it.

## Implementation

### Step 1: Create ConversationManager
**File: `core/src/main/java/com/letta/mobile/data/repository/ConversationManager.kt`**

```kotlin
package com.letta.mobile.data.repository

import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import javax.inject.Inject
import javax.inject.Singleton

@Singleton
class ConversationManager @Inject constructor(
    private val conversationRepository: ConversationRepository,
) {
    private val _activeConversations = MutableStateFlow<Map<String, String>>(emptyMap())

    /**
     * Get the active conversation ID for an agent.
     * Returns null if no conversation is active.
     */
    fun getActiveConversationId(agentId: String): String? {
        return _activeConversations.value[agentId]
    }

    /**
     * Observe the active conversation ID for an agent.
     */
    fun observeActiveConversationId(agentId: String): StateFlow<String?> {
        // Return a derived StateFlow that emits when this agent's conversation changes
        return MutableStateFlow(_activeConversations.value[agentId]).also { flow ->
            // This is simplified - in production use combine/map
        }
    }

    /**
     * Set the active conversation for an agent.
     * This is the ONLY way to change the active conversation.
     */
    fun setActiveConversation(agentId: String, conversationId: String) {
        _activeConversations.value = _activeConversations.value.toMutableMap().apply {
            put(agentId, conversationId)
        }
        android.util.Log.d("ConversationManager", "Set active conversation: agent=$agentId, conv=$conversationId")
    }

    /**
     * Clear the active conversation for an agent.
     */
    fun clearActiveConversation(agentId: String) {
        _activeConversations.value = _activeConversations.value.toMutableMap().apply {
            remove(agentId)
        }
    }

    /**
     * Resolve the most recent conversation for an agent.
     * Sets it as active and returns the ID.
     */
    suspend fun resolveAndSetActiveConversation(agentId: String, maxAgeMs: Long = 30_000L): String? {
        conversationRepository.refreshConversationsIfStale(agentId, maxAgeMs)
        val conversations = conversationRepository.getCachedConversations(agentId)
        val mostRecent = conversations
            .sortedByDescending { it.lastMessageAt ?: it.createdAt ?: "" }
            .firstOrNull()

        return mostRecent?.id?.also { convId ->
            setActiveConversation(agentId, convId)
        }
    }

    /**
     * Create a new conversation and set it as active.
     */
    suspend fun createAndSetActiveConversation(agentId: String, summary: String? = null): String {
        val conversation = conversationRepository.createConversation(agentId, summary)
        setActiveConversation(agentId, conversation.id)
        return conversation.id
    }
}
```

