private fun resolveConversationAndLoad() {
    viewModelScope.launch {
        _uiState.value = _uiState.value.copy(
            conversationState = ConversationState.Loading
        )

        try {
            val resolvedId = resolveConversation()
            if (resolvedId != null) {
                activeConversationId = resolvedId
                _uiState.value = _uiState.value.copy(
                    conversationState = ConversationState.Ready(resolvedId)
                )
                loadMessagesInternal()
            } else {
                // No conversations exist for this agent
                _uiState.value = _uiState.value.copy(
                    conversationState = ConversationState.NoConversation(canCreate = true),
                    isLoadingMessages = false
                )
            }
        } catch (e: Exception) {
            android.util.Log.e("ChatViewModel", "Failed to resolve conversation", e)
            _uiState.value = _uiState.value.copy(
                conversationState = ConversationState.Error(
                    message = "Failed to load conversation: ${e.message}",
                    canRetry = true
                ),
                isLoadingMessages = false
            )
        }

        initialMessage?.let { message ->
            if (message.isNotBlank() && activeConversationId != null) {
                sendMessage(message)
            }
        }
    }
}

private suspend fun resolveConversation(): String? {
    conversationRepository.refreshConversationsIfStale(agentId, CONVERSATION_CACHE_TTL_MS)
    val conversations = conversationRepository.getCachedConversations(agentId)
    return conversations
        .sortedByDescending { it.lastMessageAt ?: it.createdAt ?: "" }
        .firstOrNull()
        ?.id
}
