### Step 3: Update mergeMessageLists() to match by content
**File: `core/src/main/java/com/letta/mobile/data/repository/MessageRepository.kt`**

```kotlin
private fun mergeMessageLists(existing: List<AppMessage>, incoming: List<AppMessage>): List<AppMessage> {
    val merged = LinkedHashMap<String, AppMessage>()

    // First, add all existing non-pending messages
    existing.filter { !it.isPending }.forEach { merged[it.id] = it }

    // Then add incoming messages (these are authoritative)
    incoming.forEach { serverMsg ->
        merged[serverMsg.id] = serverMsg
    }

    // Now handle pending messages:
    // If a pending message's content matches a server message, drop the pending one
    // Otherwise keep it (server hasn't persisted yet)
    val serverContentHashes = incoming.map { it.contentHash() }.toSet()
    existing.filter { it.isPending }.forEach { pendingMsg ->
        if (pendingMsg.contentHash() !in serverContentHashes) {
            // Server doesn't have this message yet, keep it
            merged[pendingMsg.id] = pendingMsg
        }
        // If content matches, we drop the pending (server version wins)
    }

    return merged.values.toList().sortedBy { it.date }
}
```

