        }
    }

    fun sendMessage(text: String): Flow<StreamEvent> {
        val convId = conversationId
            ?: return flowOf(StreamEvent.Error("No conversation selected"))

        return messageRepository.sendMessage(agentId, text, convId)
            .map { streamState ->
                when (streamState) {
                    is StreamState.Sending -> StreamEvent.Sending
                    is StreamState.Streaming -> StreamEvent.Streaming(
                        streamState.messages.map { it.toChatMessage() }
                    )
                    is StreamState.Complete -> StreamEvent.Complete(
                        streamState.messages.map { it.toChatMessage() }
                    )
                    is StreamState.ToolExecution -> StreamEvent.ToolExecution(streamState.toolName)
                    is StreamState.Error -> StreamEvent.Error(streamState.message)
                }
            }
    }

    suspend fun getMessages(): List<ChatMessage> {
        val convId = conversationId ?: return emptyList()
        return messageRepository.fetchMessages(agentId, convId)
            .map { it.toChatMessage() }
    }

    fun observeMessages(): Flow<List<ChatMessage>> {
        val convId = conversationId ?: return flowOf(emptyList())
        return messageRepository.getMessages(agentId, convId)
            .map { messages -> messages.map { it.toChatMessage() } }
    }

    // NO INTERNAL STATE - everything delegates to repositories
}
